#pragma mark - ui事件
- (void)play:(UIButton *)button {
    // copyButton显示点击效果
    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    NSURL *url = [[NSBundle mainBundle] URLForResource:self.mode withExtension:nil];
    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];

    // 请求权限以在后台播放音频，并允许与其它应用音频混合
    static dispatch_once_t onceToken;
     dispatch_once(&onceToken, ^{   // 只在app启动时设置（执行）一次
       AVAudioSession *audioSession = [AVAudioSession sharedInstance];  // 获取音频会话单例对象
       [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];   // 设置音频会话类别
             /*
                AVAudioSessionCategoryPlayback ：表示 app 将播放音频
                AVAudioSessionCategoryOptionMixWithOthers ：这个选项表示允许与其他音频应用混合播放
                error:nil ：表示忽略任何可能出现的错误（通常应该是捕获并处理可能出现的错误，这里我们选择忽略）
              */
       [audioSession setActive:YES error:nil];  // 激活音频会话（这里同样忽略错误）
     });

    _doneButton.hidden = YES;
    _stopButton.hidden = NO;

    [self.player play];
    //开始计时
    CMTime targetTime = CMTimeMake(_targetSeconds*30, 1); // 分钟
    __weak typeof(self) weakSelf = self;
    [self.player addBoundaryTimeObserverForTimes:@[[NSValue valueWithCMTime:targetTime]]
                                           queue:dispatch_get_main_queue()
                                      usingBlock:^{
//        [weakSelf stop:nil]; // 触发暂停
//        _doneButton.layer.hidden = NO;
//        _stopButton.layer.hidden = YES;
        [weakSelf stop:_stopButton];
    }];

    [[NSNotificationCenter defaultCenter]addObserver:self selector:@selector(runLoopTheMovie:) name:AVPlayerItemDidPlayToEndTimeNotification object:_player.currentItem];
}

- (void)stop:(UIButton *)button {
    // copyButton显示点击效果
    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    _doneButton.layer.hidden = NO;
    _stopButton.layer.hidden = YES;
    [self.player pause];
    //暂停定时器

}

- (void)go:(UIButton *)button {

    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    UIViewController *parentVC = [self findParentViewController];
    ModePickerViewController *modeVc = [[ModePickerViewController alloc] init];

    // 设置回调 block
    __weak typeof(self) weakSelf = self; // 避免循环引用
    modeVc.returnBlock = ^(NSString *returnedValue) {
        __strong typeof(weakSelf) strongSelf = weakSelf;

        // 这里处理回传的数据
        NSLog(@"收到回传值: %@", returnedValue);
        strongSelf.mode = returnedValue; // 保存到属性

        // 刷新UI或其他操作
        //            [strongSelf updateUI];

        if(returnedValue == @"A_white.mp3"){
            self.selectedLabel.text = NSLocalizedString(@"White Noise", nil);
        }else if(returnedValue == @"A_pink.mp3"){
            self.selectedLabel.text = NSLocalizedString(@"Pink Noise", nil);
        }else{
            self.selectedLabel.text = NSLocalizedString(@"Brown Noise", nil);
        }
    };

    [parentVC presentViewController:modeVc animated:YES completion:^{
        [SVProgressHUD dismiss];
    }];
}

- (UIViewController *)findParentViewController {
    UIResponder *responder = self;
    while (responder) {
        if ([responder isKindOfClass:[UIViewController class]]) {
            return (UIViewController *)responder;
        }
        responder = [responder nextResponder];
    }
    return nil;
}

//接收播放完成的通知
- (void)runLoopTheMovie:(NSNotification *)notification {
    NSURL *url = [[NSBundle mainBundle] URLForResource:self.mode withExtension:nil];
    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
    [_player play];
}

- (void)customTimeTapped:(UITapGestureRecognizer *)sender {
    [self showCustomTimeAlert];
}

- (void)showCustomTimeAlert {
    NSLog(@"tap");
    UIViewController *currentVC = [self findCurrentViewController];
    UIAlertController *alertController = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"Enter Time",nil) message:nil preferredStyle:UIAlertControllerStyleAlert];
    [alertController addTextFieldWithConfigurationHandler:^(UITextField * _Nonnull textField) {
        textField.placeholder = NSLocalizedString(@"Enter",nil);
        textField.keyboardType = UIKeyboardTypeNumberPad;
    }];
    UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"Cancel",nil) style:UIAlertActionStyleCancel handler:^(UIAlertAction * _Nonnull action) { }];
    UIAlertAction *confirmAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"OK",nil) style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        UITextField *textField = alertController.textFields.firstObject;
        if (textField.text.length > 0) {
            NSString *newTime = textField.text;
            self.targetSeconds = [newTime intValue];
            // 把 botton60 的标题改成用户输入的分钟数
            [self.timeview.botton60 setTitle:[NSString stringWithFormat:@"%@ min", newTime] forState:UIControlStateNormal];
            [self.timeview.botton60 setTitle:[NSString stringWithFormat:@"%@ min", newTime] forState:UIControlStateSelected];
        } else {
            UIAlertController *warningAlert = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"Notice",nil) message:NSLocalizedString(@"No input",nil) preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *okAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"OK",nil) style:UIAlertActionStyleDefault handler:nil];
            [warningAlert addAction:okAction];
            [currentVC presentViewController:warningAlert animated:YES completion:nil];
        }
    }];
    [alertController addAction:cancelAction];
    [alertController addAction:confirmAction];
    [currentVC presentViewController:alertController animated:YES completion:nil];
}

- (UIViewController *)findCurrentViewController {
    UIResponder *responder = self;
    while ((responder = [responder nextResponder])) {
        if ([responder isKindOfClass:[UIViewController class]]) {
            return (UIViewController *)responder;
        }
    }
    return nil;
}

